import { bbox, each, pick, getBoundingRect } from '../../utils/zcutils';
import { isSvgElement } from '../../utils/zcsvgutils';

function exportMark(parser, cache) {
    let { as, name, element } = parser;

    if (!as) {
        return;
    }

    let exported = (parser._as = {});
    each(as, value => (exported[value] = []));

    element.each(function() {
        let bb = isSvgElement(this) ? bbox(this) : getBoundingRect(this);
        each(as, (value, attr) => exported[value].push(pick(bb[attr], bb)));
    });
}

export { exportMark };
